func:
const BAT_LABEL = [
"Unknown",
"AGM",
"Liquid",
"LFP",
"LFP High",
"LFP Med",
"LFP Low"
];

const NL_LABEL=[
"Always On",
"D2D",
"DD",
"MN"
];


const serial = msg.payload;

const out=new Array(16).fill(null);


if(!serial){

 flow.set(
 'selected_serial',
 null
 );

 out[0]={
 payload:
 `
 <div style="
 text-align:center;
 padding:30px;
 color:#64748b">
 Select device
 </div>
 `
 };

 node.send(out);
 return null;
}


flow.set(
'selected_serial',
serial
);


const cache =
global.get('settings_cache') || {};


const s =
cache[serial] || {};


const onlineMap =
global.get('online_map') || {};


const online =
!onlineMap[serial] ||
onlineMap[serial].online !== false;


const color =
online ? '#22c55e':'#ef4444';



out[0]={
payload:
`

<div class="device-summary">

<div class="device-main">

<div class="device-title-row">

<div class="device-dot"
style="background:${color}">
</div>


<div>

<div class="device-name">
${serial}
</div>


<div class="device-status"
style="color:${color}">
${online?'ONLINE':'OFFLINE'}
</div>


</div>

</div>

</div>



<div class="device-stats">


<div>
<span>Battery</span>
<strong>
${BAT_LABEL[s.battery_type]||'-'}
</strong>
</div>


<div>
<span>Capacity</span>
<strong>
${s.capacity_ah||'-'} Ah
</strong>
</div>


<div>
<span>LVD</span>
<strong>
${s.lvd_mode?'Voltage':'SOC'}
</strong>
</div>


<div>
<span>Mode</span>
<strong>
${NL_LABEL[s.night_mode]||'-'}
</strong>
</div>


</div>


</div>

`
};



// widgets
out[1]={payload:s.battery_type ? String(s.battery_type) : ""};
out[2]={payload:s.capacity_ah || ""};
out[3]={payload:s.lvd_voltage_mv || ""};
out[4]={payload:s.lvd_mode ?? ""};

out[5]={payload:s.night_mode ? String(s.night_mode) : ""};
out[6]={payload:s.evening_minutes || ""};
out[7]={payload:s.morning_minutes || ""};
out[8]={payload:s.night_threshold_mv || ""};

out[9]={payload:s.dimming_mode ? String(s.dimming_mode) : ""};
out[10]={payload:s.evening_minutes_dimming || ""};
out[11]={payload:s.morning_minutes_dimming || ""};

out[12]={payload:s.dimming_pct || ""};
out[13]={payload:s.base_dimming_pct || ""};

out[14]={payload:s.dali_power_enable ?? ""};
out[15]={payload:s.alc_dimming_enable ?? ""};

node.send(out);

return null;

// @refactor:v1
// Store widget value in unified widget_state map (keyed by widget topic).
const s = flow.get('widget_state') || {};
s[msg.topic] = msg.payload;
flow.set('widget_state', s);
return null;

if (msg.topic === 'send')   return [msg, null];
if (msg.topic === 'reload') return [null, msg];
return null;

const serial = flow.get('selected_serial');
if (!serial) return null;
msg.payload = serial;
return msg;

// @refactor:v1
// Build a SET_SETTINGS command containing only the fields that diverge from
// the device's last known settings. Inputs:
//   - global.settings_cache[serial]  baseline (kept in sync by Ingestion tab)
//   - flow.widget_state              current widget values, by widget topic
// No flow-level baseline clone -- single source of truth.

const serial = flow.get('selected_serial');
if (!serial) return null;

const baseline = (global.get('settings_cache') || {})[serial];
if (!baseline) { node.warn('No settings cached for ' + serial); return null; }

const fleet = global.get('fleet') || {};
const dev   = fleet[serial] || {};
const zone  = dev.zone       || 'default';
const gw    = dev.gateway_id || 'unknown';

const ws     = flow.get('widget_state') || {};
const toInt  = (v) => { const n = parseInt(v); return isNaN(n) ? undefined : n; };
const toBool = (v) => v === true || v === 'true';

const current = {
    battery_type:            toInt(ws['w-bat-type']),
    capacity_ah:             toInt(ws['w-cap-ah']),
    lvd_voltage_mv:          toInt(ws['w-lvd-v']),
    lvd_mode:                toBool(ws['w-lvd-mode']) ? 1 : 0,
    night_mode:              toInt(ws['w-night-mode']),
    evening_minutes:         toInt(ws['w-eve-min']),
    morning_minutes:         toInt(ws['w-morn-min']),
    night_threshold_mv:      toInt(ws['w-night-thresh']),
    dimming_mode:            toInt(ws['w-dim-mode']),
    evening_minutes_dimming: toInt(ws['w-dim-eve-min']),
    morning_minutes_dimming: toInt(ws['w-dim-morn-min']),
    dimming_pct:             toInt(ws['w-dim-pct']),
    base_dimming_pct:        toInt(ws['w-base-dim-pct']),
};

const setSettings = {};
let changeCount = 0;
for (const [k, v] of Object.entries(current)) {
    if (v !== undefined && v !== baseline[k]) {
        setSettings[k] = v;
        changeCount++;
    }
}

const curDali = toBool(ws['w-dali']);
const curAlc  = toBool(ws['w-alc']);
if (curDali !== !!baseline.dali_power_enable || curAlc !== !!baseline.alc_dimming_enable) {
    setSettings.advanced_flags = (curDali ? 1 : 0) | (curAlc ? 2 : 0);
    changeCount++;
}

if (changeCount === 0) { node.warn('No changes vs baseline for ' + serial); return null; }

const requestId = serial + '_' + Date.now();
msg.topic   = 'mppt/' + zone + '/' + gw + '/' + serial + '/cmd';
msg.payload = { request_id: requestId, timestamp: Math.floor(Date.now()/1000), set_settings: setSettings };

// Log entry, bounded to 50.
const ts    = new Date().toLocaleTimeString();
const entry = '<div style="font-size:12px;padding:4px 0;border-bottom:1px solid #334155">' +
    '<span style="color:#64748b">' + ts + '</span> ' +
    '<span style="color:#3b82f6;font-weight:600">SEND</span> ' +
    serial + ' - ' + requestId +
    ' <span style="color:#eab308">(' + changeCount + ' changed)</span></div>';
const log = flow.get('cmd_log_arr') || [];
log.unshift(entry);
if (log.length > 50) log.length = 50;
flow.set('cmd_log_arr', log);

return msg;

const log = flow.get('cmd_log_arr') || [];

msg.payload =
`
<div class="cmdlog-container">
    ${log.length ? log.join('') :
    '<span class="cmdlog-empty">No commands sent yet.</span>'}
</div>
`;

return msg;

// @refactor:v1
// Append an ACK entry to the bounded log array and render the full log.

const p      = msg.topic.split('/');
const serial = p.length >= 4 ? p[3] : '?';
const ts     = new Date().toLocaleTimeString();
const pl     = msg.payload || {};

const ok     = pl.ok;
const reason = pl.reason || '';
const reqId  = pl.request_id || '';

const color = ok ? '#4ade80' : '#f87171';
const label = ok ? 'ACK \u2713' : 'ACK \u2717';
const idStr = reqId ? ' <span style="color:#475569">[' + reqId.split('_').pop() + ']</span>' : '';

const entry =
    '<div style="font-size:12px;padding:4px 0;border-bottom:1px solid #1e293b">' +
    '<span style="color:#475569">' + ts + '</span> ' +
    '<span style="color:' + color + ';font-weight:700">' + label + '</span> ' +
    '<span style="color:#94a3b8">' + serial + '</span>' + idStr +
    (reason ? '<span style="color:#64748b"> - ' + reason + '</span>' : '') +
    '</div>';

const log = flow.get('cmd_log_arr') || [];
log.unshift(entry);
if (log.length > 50) log.length = 50;
flow.set('cmd_log_arr', log);

msg.payload =
`
<div class="cmdlog-container">
    ${log.join('')}
</div>
`;

return msg;

const fleet     = global.get('fleet')      || {};
const onlineMap = global.get('online_map') || {};

const selected = flow.get('selected_serial') || "";

const opts = Object.keys(fleet).sort().map(s => {

    const dev = fleet[s] || {};
    const zone = dev.zone || 'default';

    const online =
        onlineMap[s] ?
        onlineMap[s].online !== false :
        true;

    return {
        value: s,
        label:
            s +
            ' [' + zone + '] ' +
            (online ? '●' : '○')
    };
});

opts.unshift({
    value:"",
    label:"-- Select Device --"
});


msg.payload = opts;


// keep current selection
msg.ui_update = {
    options: opts,
    value: selected
};


return msg;

const p      = msg.topic ? msg.topic.split('/') : [];
const serial = p[3];
if (!serial) return [null, {}];
const selected = flow.get('selected_serial');
return (selected === serial) ? [{ payload: serial }, {}] : [null, {}];

const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial = p[3];
const d = msg.payload || {};
const infoMap = global.get('info_map') || {};

infoMap[serial] = {
    type:             d.device_type || d.type || '',
    production_date:  d.production_date || '',
    hw_version:       d.hw_version || 0,
    serial_number:    d.serial_number || serial
};

global.set('info_map', infoMap);
return null;

flow.set('temp_lat', msg.payload.lat);
flow.set('temp_lon', msg.payload.lon);
return null;

const serial = flow.get('selected_serial');
if (!serial) { node.warn('No device selected'); return null; }

const lat = flow.get('temp_lat');
const lon = flow.get('temp_lon');
if (lat === undefined || lon === undefined) { node.warn('No location selected on map'); return null; }

// Update cache
const locCache = global.get('location_cache') || {};
locCache[serial] = { lat, lon };
global.set('location_cache', locCache);

msg.payload = { lat, lon };
msg.tags = { serial };
return [msg, { payload: 'Location saved for ' + serial, _ui: { action: 'notify', type: 'success' } }];

const serial = msg.payload;
const locMap = global.get('location_cache') || {};
if (locMap[serial]) {
    return { payload: locMap[serial] };
}
return null;

const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial = p[3];
const d = msg.payload || {};

const infoMap = global.get('info_map') || {};
infoMap[serial] = {
    type:            d.device_type || '',
    production_date: d.production_date || '',
    hw_version:      d.hw_version || 0,
    serial_number:   d.serial_number || serial,
};
global.set('info_map', infoMap);

// Forward so the control tab device list refreshes
msg.payload = serial;
return msg;

const BAT_MAP={BATTERY_TYPE_UNKNOWN:0,BATTERY_AGM:1,BATTERY_LIQUID:2,BATTERY_LFP:3,BATTERY_LFP_HIGH_TEMP:4,BATTERY_LFP_MEDIUM_TEMP:5,BATTERY_LFP_LOW_TEMP:6};
const LVD_MAP={LVD_MODE_SOC:0,LVD_MODE_VOLTAGE:1};
const NIGHT_MAP={NIGHT_MODE_ALWAYS_ON:0,NIGHT_MODE_D2D:1,NIGHT_MODE_DD:2,NIGHT_MODE_MN:3};
function normEnum(v,map){if(v===null||v===undefined)return 0;if(typeof v==='object'&&'value'in v)v=v.value;if(typeof v==='string'&&map[v]!==undefined)return map[v];return parseInt(v)||0;}

const p = msg.topic.split('/');
const serial = p[3];
const d = msg.payload || {};
const settingsMap = global.get('settings_cache') || {};

settingsMap[serial] = {
    battery_type:               normEnum(d.battery_type, BAT_MAP),
    capacity_ah:                d.capacity_ah             || 100,
    lvd_voltage_mv:             d.lvd_voltage_mv           || 11000,
    lvd_mode:                   normEnum(d.lvd_mode, LVD_MAP),
    night_mode:                 normEnum(d.night_mode, NIGHT_MAP),
    evening_minutes:            d.evening_minutes          || 0,
    morning_minutes:            d.morning_minutes          || 0,
    night_threshold_mv:         d.night_threshold_mv       || 11500,
    dimming_mode:               normEnum(d.dimming_mode, NIGHT_MAP),
    evening_minutes_dimming:    d.evening_minutes_dimming  || 0,
    morning_minutes_dimming:    d.morning_minutes_dimming  || 0,
    dimming_pct:                d.dimming_pct              || 100,
    base_dimming_pct:           d.base_dimming_pct         || 30,
    dali_power_enable:          !!(d.advanced_flags & 1),
    alc_dimming_enable:         !!(d.advanced_flags & 2),
    advanced_flags:             d.advanced_flags           || 0
};
global.set('settings_cache', settingsMap);

// Re-populate control panel if this device is currently selected
const selected = flow.get('selected_serial');
return (selected === serial) ? [{ payload: serial }] : [null];

const p = msg.topic.split('/');
const serial = p[3];
const zone = p[1];
const isOnline = msg.payload.toString().trim() === '1';
const key = 'online_' + serial;
const wasOnline = context.get(key);
context.set(key, isOnline);

const onlineMap = global.get('online_map') || {};
onlineMap[serial] = { online: isOnline, ts: new Date().toISOString() };
global.set('online_map', onlineMap);

if (!isOnline && wasOnline !== false) {
    const ts = new Date().toISOString();
    return [{ payload: {
        severity: 'critical', condition: 'Device offline',
        emailNeeded: true, serial, zone, ts,
        subject: '[MPPT CRITICAL] ' + serial + ' offline',
        body: 'Device ' + serial + ' (zone: ' + zone + ') went offline at ' + ts
    }}];
}
if (isOnline && wasOnline === false) {
    node.log(serial + ' back online');
}
return null;

if (!msg.payload || !msg.payload.subject) return null;
msg.topic = msg.payload.subject;
msg.payload = msg.payload.body;
return msg;

const p = msg.topic.split('/');
if (p.length < 5) return [null, null, null];
const zone  = p[1];
const gw    = p[2];
const serial= p[3];
const d     = msg.payload || {};

// Pull hw_version from info cache as fallback
const info  = (global.get('info_map') || {})[serial] || {};
const hwVer = String(d.hw_version || info.hw_version || 0);

// Fault mask -> individual boolean fields for InfluxDB
const fm = d.fault_mask || 0;
const faults = {
    battery_over_voltage:   (fm & 0x01) ? 1 : 0,
    pv_over_voltage:        (fm & 0x02) ? 1 : 0,
    controller_over_temp:   (fm & 0x04) ? 1 : 0,
    charge_over_current:    (fm & 0x08) ? 1 : 0,
    lvd_active:             (fm & 0x10) ? 1 : 0,
    over_discharge_current: (fm & 0x20) ? 1 : 0,
    battery_over_temp:      (fm & 0x40) ? 1 : 0,
    battery_under_temp:     (fm & 0x80) ? 1 : 0,
};

//  Update fleet state (used by overview dashboard)
const fleet = global.get('fleet') || {};
fleet[serial] = {
    serial, zone, gateway_id: gw, hw_version: hwVer,
    bat: {
        battery_voltage_mv:      d.battery_voltage_mv      || 0,
        battery_soc_pct:         d.battery_soc_pct         || 0,
        charge_current_ma:       d.charge_current_ma10 * 10 || 0,
        charge_power_w:          d.charge_power_w          || 0,
        end_of_charge_voltage_mv:d.end_of_charge_voltage_mv|| 0,
        charge_mode:             d.charge_mode             || 'unknown',
        is_night:                !!( d.flags & (1 << 1) ),
        bat_op_days:             d.bat_op_days             || 0,
        energy_in_daily_wh:      d.energy_in_daily_wh      || 0,
        energy_out_daily_wh:     d.energy_out_daily_wh     || 0,
        energy_retained_wh:      d.energy_retained_wh      || 0,
        detected:                !!( d.flags & (1 << 0) ),
        charge_state_mask:       d.charge_state_mask       || 0,
    },
    load: {
        load_on:         !!( d.flags & (1 << 2) ),
        night_mode:      !!( d.flags & (1 << 3) ),
        lvd_active:      !!( d.flags & (1 << 4) ),
        user_disconnect: !!( d.flags & (1 << 5) ),
        over_current:    !!( d.flags & (1 << 6) ),
        load_current_ma:  d.load_current_ma10 * 10 || 0,
        load_power_w:       d.load_power_w      || 0,
        state_mask:         d.load_state_mask   || 0,
    },
    pv: {
        pv_voltage_mv:        d.pv_voltage_mv        || 0,
        pv_target_voltage_mv: d.pv_target_voltage_mv || 0,
        detected:             !!( d.flags & (1 << 7) ),
    },
    faults,
    ts: Math.floor(Date.now() / 1000),
};
global.set('fleet', fleet);

const dev = fleet[serial];
const tags = { zone, gateway_id: gw, serial, hw_version: hwVer,
               charge_mode: d.charge_mode || 'unknown' };

// Output 1: influxdb telemetry fields
const telFields = {
    battery_voltage_mv:   d.battery_voltage_mv   || 0,
    soc_pct:              d.battery_soc_pct      || 0,
    charge_current_ma:  d.charge_current_ma10 * 10 || 0,
    charge_power_w:       d.charge_power_w       || 0,
    is_night:             dev.bat.is_night        ? 1 : 0,
    energy_in_daily_wh:   d.energy_in_daily_wh   || 0,
    energy_out_daily_wh:  d.energy_out_daily_wh  || 0,
    energy_retained_wh:   d.energy_retained_wh   || 0,
    load_on:              dev.load.load_on        ? 1 : 0,
    lvd_active:           (dev.load.lvd_active || faults.lvd_active) ? 1 : 0,
    load_current_ma:    d.load_current_ma10  * 10 || 0,
    load_power_w:         d.load_power_w          || 0,
    pv_voltage_mv:        d.pv_voltage_mv         || 0,
    pv_target_voltage_mv: d.pv_target_voltage_mv  || 0,
    internal_temp_c:      d.internal_temp_c       || 0,
    external_temp_c:      d.external_temp_c       || 0,
    led_voltage_mv:       d.led_voltage_mv        || 0,
    led_current_ma:     d.led_current_ma10 * 10      || 0,
    led_power_w:          d.led_power_w           || 0,
    load_state_mask:      d.load_state_mask       || 0,
    charge_state_mask:    d.charge_state_mask     || 0,
    flags:                d.flags                 || 0,
};

// Output 0: alert msg
const alertMsg = {
    serial, zone,
    soc_pct:   d.battery_soc_pct || 0,
    faults,
    lvd_active: dev.load.lvd_active,
    ts: new Date().toISOString(),
};

return [
    { payload: alertMsg },
    { payload: [telFields, tags] },
    { payload: [faults,   tags] },
];

const { serial, zone, soc_pct, faults, lvd_active, ts } = msg.payload;

const checks = [
    { cond: soc_pct > 0 && soc_pct < 10,  label: 'Battery SOC critical (' + soc_pct + '%)' },
    { cond: !!(faults.lvd_active || lvd_active), label: 'LVD active' },
    { cond: !!faults.battery_over_voltage,        label: 'Battery over voltage' },
    { cond: !!faults.over_discharge_current,      label: 'Over discharge current' },
    { cond: !!faults.battery_over_temp,           label: 'Battery over temperature' },
    { cond: !!faults.battery_under_temp,          label: 'Battery under temperature' },
];

const triggered = checks.filter(c => c.cond);
if (!triggered.length) return null;

// Emit one email per alert condition
return triggered.map(c => ({
    payload: {
        subject: '[MPPT CRITICAL] ' + serial + ' - ' + c.label,
        body:    'Device: ' + serial + '\nZone: ' + zone + '\nCondition: ' + c.label + '\nTimestamp: ' + ts,
    }
}));

const p = msg.topic.split('/');
if (p.length < 6) return [null, null, null];
const [, zone, gateway, serial,, sub] = p;

const dl  = msg.payload;
const info = (global.get('info_map') || {})[serial] || {};
const ct  = { serial, gateway_id: gateway, zone, hw_version: String(info.hw_version || 0) };

function unpackStateFlags(sf) {
    return {
        load_disconnect:  (sf >> 0) & 1,
        full_charge:      (sf >> 1) & 1,
        pv_over_current:  (sf >> 2) & 1,
        load_over_current:(sf >> 3) & 1,
        bat_over_voltage: (sf >> 4) & 1,
        low_soc:          (sf >> 5) & 1,
        temp_pv_over:     (sf >> 6) & 1,
        temp_pv_low:      (sf >> 7) & 1,
        temp_load_over:   (sf >> 8) & 1,
    };
}

function scaleEntry(e, indexKey, ahMul, socScale, isMonthly) {
    return {
        [indexKey]:      e.index          || 0,
        vbat_min_mv:     (e.vbat_min_mv   || 0) * 100,
        vbat_max_mv:     (e.vbat_max_mv   || 0) * 100,
        vpv_min_mv:      (e.vpv_min_mv    || 0) * 500,
        vpv_max_mv:      (e.vpv_max_mv    || 0) * 500,
        ah_charge_mah:   (e.ah_charge_mah || 0) * ahMul,
        ah_load_mah:     (e.ah_load_mah   || 0) * ahMul,
        il_max_ma:       (e.il_max_ma     || 0) * 500,
        ipv_max_ma:      (e.ipv_max_ma    || 0) * 500,
        soc_pct:         (e.soc_pct       || 0) * (isMonthly ? (socScale * 6.6) : (socScale)),
        ext_temp_max_c:  e.ext_temp_max_c || 0,
        ext_temp_min_c:  e.ext_temp_min_c || 0,
        nightlength_min: (e.nightlength_min|| 0) * 10,
        ...unpackStateFlags(e.state_flags  || 0),
    };
}

if (sub === 'summary') {
    return [{ payload: [{
        recorded_days:              dl.recorded_days              || 0,
        days_with_lvd:              dl.days_with_lvd              || 0,
        months_without_full_charge: dl.months_without_full_charge || 0,
        avg_morning_soc_pct:        (dl.recorded_days > 0) ? dl.avg_morning_soc_pct * 6.6 / dl.recorded_days : 0 || 0,
        total_ah_charge_mah:        dl.total_ah_charge_mah / 10   || 0,
        total_ah_load_mah:          dl.total_ah_load_mah / 10     || 0,
    }, ct] }, null, null];
}

if (sub === 'daily') {
    const msgs = (dl.daily_logs || []).map(e => ({
        payload: [scaleEntry(e, 'day_num', 100, 6.6, false),
                  { ...ct, day_index: String(e.index) }],
    }));
    return [null, msgs.length ? msgs : null, null];
}

if (sub === 'monthly') {
    const msgs = (dl.monthly_logs || []).map(e => ({
        payload: [scaleEntry(e, 'month_num', 1000, 1, true),
                  { ...ct, month_index: String(e.index) }],
    }));
    node.warn(msgs);
    return [null, null, msgs.length ? msgs : null];
}

return [null, null, null];

const fleet = global.get('fleet') || {};
const onlineMap = global.get('online_map') || {};
const serials = Object.keys(fleet).sort();

if (!serials.length) {
    const empty = '<p style="color:#94a3b8;padding:24px;text-align:center;font-style:italic">No devices detected on the network yet.</p>';
    return [{ payload: empty }, { payload: empty }];
}


let totalDevices = serials.length;
let onlineCount = 0;
let faultCount = 0;
let totalSoc = 0;
let totalCharge = 0;
let socSamples = 0;


for (const s of serials) {

    const d = fleet[s] || {};
    const om = onlineMap[s];


    if (!om || om.online) {
        onlineCount++;
    }


    if (
        d.faults &&
        (
            d.faults.any_fault ||
            Object.values(d.faults).some(v => v === 1 || v === true)
        )
    ) {
        faultCount++;
    }


    const soc = Number(d?.bat?.battery_soc_pct);
    const charge = Number(d?.bat?.charge_power_w);


    if (Number.isFinite(soc)) {
        totalSoc += soc;
        socSamples++;
    }


    if (Number.isFinite(charge)) {
        totalCharge += charge;
    }
}


const avgSoc = socSamples
    ? Math.round(totalSoc / socSamples)
    : 0;


const offlineCount = totalDevices - onlineCount;



function statCard(label, value, sub, color) {

return `
<div style="
background:#1e293b;
border:1px solid:#334155;
border-radius:14px;
min-height:160px;
padding:24px;
display:flex;
flex-direction:column;
justify-content:center;
align-items:center;
box-sizing:border-box;
">

<div style="
font-size:52px;
font-weight:800;
color:${color};
">
${value}
</div>


<div style="
margin-top:12px;
color:#94a3b8;
font-size:14px;
font-weight:700;
text-transform:uppercase;
">
${label}
</div>


${sub ? `
<div style="
margin-top:6px;
color:#64748b;
font-size:11px;
">
${sub}
</div>
` : ''}


</div>`;
}




const summaryHtml = `

<div style="
width:100%;
display:grid;
grid-template-columns:repeat(5,minmax(0,1fr));
gap:16px;
">

${statCard(
'Devices',
totalDevices,
'total',
'#3b82f6'
)}


${statCard(
'Online',
onlineCount,
offlineCount + ' offline',
'#22c55e'
)}


${statCard(
'Avg SOC',
avgSoc + '%',
'',
avgSoc > 50 ? '#22c55e' : avgSoc > 20 ? '#f59e0b' : '#ef4444'
)}


${statCard(
'Charge',
Math.round(totalCharge) + ' W',
'fleet total',
'#3b82f6'
)}


${statCard(
'Faults',
faultCount,
faultCount ? 'devices with issues' : 'all clear',
faultCount ? '#ef4444' : '#22c55e'
)}

</div>
`;




let rows = '';



for (const s of serials) {


const d = fleet[s] || {};
const om = onlineMap[s] || {online:true};


const online = om.online;



const soc =
Number(d?.bat?.battery_soc_pct) || 0;


const vbat =
(Number(d?.bat?.battery_voltage_mv) || 0) / 1000;


const icharge =
(Number(d?.bat?.charge_current_ma) || 0) / 1000;


const iload =
(Number(d?.load?.load_current_ma) || 0);



const faults =
d.faults &&
(
d.faults.any_fault ||
Object.values(d.faults).some(v => v === 1 || v === true)
);



rows += `

<tr style="border-bottom:1px solid #334155">


<td style="padding:14px 12px">

<div style="display:flex;align-items:center">


<div style="
width:8px;
height:8px;
border-radius:50%;
background:${online ? '#22c55e':'#ef4444'};
margin-right:10px;
"></div>



<div>

<div style="
font-weight:600;
color:#f1f5f9;
">
${s}
</div>


<div style="
font-size:11px;
color:#64748b;
">
${d.zone || 'N/A'} / ${d.gateway_id || 'N/A'}
</div>


</div>


</div>

</td>




<td style="padding:14px;text-align:center">


<div style="
background:#334155;
height:6px;
border-radius:999px;
">


<div style="
width:${soc}%;
height:100%;
border-radius:999px;
background:${soc > 50 ? '#22c55e' : soc > 20 ? '#f59e0b':'#ef4444'};
"></div>


</div>


<span style="
color:#f1f5f9;
font-weight:700;
">
${soc}%
</span>


</td>




<td style="text-align:center;color:#f1f5f9">
${vbat.toFixed(2)}V
</td>



<td style="
text-align:center;
color:#3b82f6;
font-weight:600;
">
${icharge.toFixed(2)}A
</td>



<td style="
text-align:center;
color:#f59e0b;
font-weight:600;
">
${iload.toFixed(2)}mA
</td>




<td style="text-align:center">

${
faults
?
`
<span style="
background:#ef4444;
color:white;
padding:4px 10px;
border-radius:999px;
font-size:11px;
font-weight:700;
">
FAULT
</span>
`
:
`
<span style="
color:#22c55e;
font-size:18px;
">
✓
</span>
`
}

</td>


</tr>

`;

}



const tableHtml = `

<div style="width:100%">


<table style="
width:100%;
table-layout:fixed;
border-collapse:collapse;
color:#94a3b8;
font-size:13px;
">


<thead>


<tr style="
border-bottom:2px solid #334155;
">


<th style="width:40%;padding:10px;text-align:left">
Device / Zone
</th>


