Load
</th>


<th style="width:10%;padding:10px;text-align:center">
Status
</th>


</tr>


</thead>


<tbody>

${rows}

</tbody>


</table>


</div>

`;



return [
    {payload: summaryHtml},
    {payload: tableHtml}
];
